const fs = require('node:fs');
const path = require('node:path');

const NORDIC_FRAMEWORK = 'nordic';
const NEXTJS_FRAMEWORK = 'nordic-nextjs';

const packageJson = JSON.parse(
  fs.readFileSync(path.resolve('package.json'), 'utf8'),
);

/**
 * Detects the framework used by the application by checking if modules are installed
 * Uses require.resolve() to verify module availability without loading them
 * @returns {'nextjs' | 'nordic' | null} 'nextjs' if next is detected, 'nordic' if nordic is detected (and not nextjs), null otherwise
 */
function detectFramework() {
  try {
    // Check for Next.js first (higher priority)
    if (packageJson.dependencies[NEXTJS_FRAMEWORK]) {
      return 'nextjs';
    }

    if (packageJson.dependencies[NORDIC_FRAMEWORK]) {
      return 'nordic';
    }
  } catch (err) {
    // Do nothing - framework detection failed
  }

  return null;
}

module.exports = {
  detectFramework,
};
